-- Bloom CRM 5.0 esquema privado
create extension if not exists pgcrypto;

create table if not exists bloom_empresas (id text primary key, owner_id uuid not null references auth.users(id) on delete cascade, nombre text, empresa text, sector text, estado text, tipo text, fecha date, fecha_proxima date, carpeta text, data jsonb not null default '{}'::jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
alter table bloom_empresas enable row level security;
drop policy if exists "owner select" on bloom_empresas; drop policy if exists "owner insert" on bloom_empresas; drop policy if exists "owner update" on bloom_empresas; drop policy if exists "owner delete" on bloom_empresas;
create policy "owner select" on bloom_empresas for select to authenticated using (owner_id = auth.uid());
create policy "owner insert" on bloom_empresas for insert to authenticated with check (owner_id = auth.uid());
create policy "owner update" on bloom_empresas for update to authenticated using (owner_id = auth.uid()) with check (owner_id = auth.uid());
create policy "owner delete" on bloom_empresas for delete to authenticated using (owner_id = auth.uid());
