insert into storage.buckets (id,name,public) values ('bloom-crm-documents','bloom-crm-documents',false) on conflict (id) do update set public=false;
drop policy if exists "private read documents" on storage.objects;drop policy if exists "private upload documents" on storage.objects;drop policy if exists "private update documents" on storage.objects;drop policy if exists "private delete documents" on storage.objects;
create policy "private read documents" on storage.objects for select to authenticated using (bucket_id='bloom-crm-documents' and (storage.foldername(name))[1]=auth.uid()::text);
create policy "private upload documents" on storage.objects for insert to authenticated with check (bucket_id='bloom-crm-documents' and (storage.foldername(name))[1]=auth.uid()::text);
create policy "private update documents" on storage.objects for update to authenticated using (bucket_id='bloom-crm-documents' and (storage.foldername(name))[1]=auth.uid()::text) with check (bucket_id='bloom-crm-documents' and (storage.foldername(name))[1]=auth.uid()::text);
create policy "private delete documents" on storage.objects for delete to authenticated using (bucket_id='bloom-crm-documents' and (storage.foldername(name))[1]=auth.uid()::text);